## Refactor plan

1. **Keep public API callback-based** — wrap an internal `async` function and bridge via `.then(ok, err)`.
2. **Promisify collaborators** — but split into two groups:
   - **Primary ops** (`startTransaction`, `reserve`, `charge`, `saveOrder`, `commit`, `notifier.send`): promisify normally; errors reject.
   - **Cleanup ops** (`rollback`, `inventory.release`, `payment.refund`): wrap in promises that **always resolve**, to preserve the original semantic of swallowing cleanup errors (empty `() => ...` callbacks).
3. **Mirror compensation chains** with sequential `await`s inside `try/catch` — each catch rethrows the original error after cleanup.
4. **Commit failure stays uncompensated** — original calls `callback(err)` with no rollback/refund. Preserve that.
5. **Notify failure stays non-fatal** — `console.warn` and return the order.

## Code

```javascript
// lib/order_processor.js
const { promisify } = require('util');
const db = require('./db');
const payment = require('./payment');
const inventory = require('./inventory');
const notifier = require('./notifier');

const pStartTransaction = promisify(db.startTransaction);
const pSaveOrder        = promisify(db.saveOrder);
const pReserve          = promisify(inventory.reserve);
const pCharge           = promisify(payment.charge);
const pNotify           = promisify(notifier.send);

const pCommit   = (tx)        => new Promise((res, rej) => tx.commit(err => err ? rej(err) : res()));
const pRollback = (tx)        => new Promise(res => tx.rollback(() => res()));
const pRelease  = (tx, resId) => new Promise(res => inventory.release(tx, resId, () => res()));
const pRefund   = (chargeId)  => new Promise(res => payment.refund(chargeId, () => res()));

async function processOrderAsync(orderId, userId, items) {
  const tx = await pStartTransaction();

  let reservation;
  try {
    reservation = await pReserve(tx, items);
  } catch (err) {
    await pRollback(tx);
    throw err;
  }

  let charge;
  try {
    charge = await pCharge(userId, reservation.total);
  } catch (err) {
    await pRelease(tx, reservation.id);
    await pRollback(tx);
    throw err;
  }

  let order;
  try {
    order = await pSaveOrder(tx, orderId, {
      userId, items, reservationId: reservation.id, chargeId: charge.id,
    });
  } catch (err) {
    await pRefund(charge.id);
    await pRelease(tx, reservation.id);
    await pRollback(tx);
    throw err;
  }

  await pCommit(tx); // commit failure: no compensation, matches original

  try {
    await pNotify(userId, 'order_placed', order);
  } catch (notifyErr) {
    console.warn('notify failed:', notifyErr);
  }

  return order;
}

function processOrder(orderId, userId, items, callback) {
  processOrderAsync(orderId, userId, items).then(
    order => callback(null, order),
    err   => callback(err),
  );
}

module.exports = { processOrder };
```

## Semantic checklist vs. original

| Path | Original | Refactor |
|---|---|---|
| `startTransaction` fails | `callback(err)` | reject → `callback(err)` |
| `reserve` fails | rollback, `callback(err)` | rollback, throw |
| `charge` fails | release, rollback, `callback(err)` | release, rollback, throw |
| `saveOrder` fails | refund, release, rollback, `callback(err)` | refund, release, rollback, throw |
| `commit` fails | `callback(err)` (no cleanup) | throw (no cleanup) |
| `notify` fails | `console.warn`, `callback(null, order)` | `console.warn`, return `order` |
| cleanup errors | swallowed | swallowed (always-resolve wrappers) |
